</div><!-- /main -->

<script>
// NAV 활성화
const sections = document.querySelectorAll('.section');
const navLinks = document.querySelectorAll('.nav-link');
window.addEventListener('scroll', () => {
  let cur = '';
  sections.forEach(s => { if (window.scrollY >= s.offsetTop - 80) cur = s.id; });
  navLinks.forEach(l => {
    l.classList.toggle('active', l.getAttribute('href') === '#' + cur);
  });
});

// 탭 전환
function switchTab(btn, panelId) {
  const bar = btn.closest('.tab-bar');
  const section = bar.closest('.section, .tab-wrap') || bar.parentElement;
  bar.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  const panels = section.querySelectorAll('.tab-panel');
  panels.forEach(p => p.classList.remove('active'));
  const target = section.querySelector('#' + panelId);
  if (target) target.classList.add('active');
}

// FAQ 토글
function toggleFaq(el) {
  el.closest('.faq-item').classList.toggle('open');
}

// 복사 기능
function copyMsg(id) {
  const el = document.getElementById(id);
  navigator.clipboard.writeText(el.innerText).then(() => {
    const btn = el.previousElementSibling;
    const orig = btn.innerText;
    btn.innerText = '복사됨 ✓';
    btn.style.background = 'var(--accent)';
    btn.style.color = '#000';
    setTimeout(() => { btn.innerText = orig; btn.style.background = ''; btn.style.color = ''; }, 2000);
  });
}

// 스크롤 애니메이션
const observer = new IntersectionObserver(entries => {
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); });
}, { threshold: 0.08 });
document.querySelectorAll('.fade-up').forEach(el => observer.observe(el));
</script>

</body>
</html>
