<style>
:root {
  --bg: #0f0f10;
  --bg2: #17171a;
  --surface: #22222a;
  --surface2: #2a2a34;
  --border: rgba(255,255,255,0.07);
  --border2: rgba(255,255,255,0.13);
  --text: #e8e6e0;
  --text2: #9a9891;
  --text3: #55534f;
  --accent: #c8f060;
  --blue: #5b9cf6;
  --blue-dim: rgba(91,156,246,0.13);
  --teal: #3dd6a3;
  --teal-dim: rgba(61,214,163,0.11);
  --purple: #a78bfa;
  --purple-dim: rgba(167,139,250,0.12);
  --amber: #fbbf24;
  --amber-dim: rgba(251,191,36,0.12);
  --orange: #fb923c;
  --orange-dim: rgba(251,146,60,0.12);
  --red: #f87171;
  --font-d: 'DM Serif Display', serif;
  --font-b: 'Noto Sans KR', sans-serif;
  --font-m: 'JetBrains Mono', monospace;
  --r: 10px;
  --rl: 16px;
}
*{margin:0;padding:0;box-sizing:border-box;}
body{background:var(--bg);color:var(--text);font-family:var(--font-b);font-size:14px;line-height:1.7;}

/* ── NAV ── */
.nav{position:sticky;top:0;z-index:100;background:rgba(15,15,16,0.93);backdrop-filter:blur(14px);border-bottom:1px solid var(--border);display:flex;align-items:center;padding:0 28px;height:50px;gap:0;}
.nav-logo{font-family:var(--font-m);font-size:11px;color:var(--accent);letter-spacing:.1em;margin-right:28px;white-space:nowrap;}
.nav-links{display:flex;overflow-x:auto;scrollbar-width:none;}
.nav-links::-webkit-scrollbar{display:none;}
.nav-link{padding:0 13px;height:50px;display:flex;align-items:center;font-size:12px;color:var(--text2);cursor:pointer;border-bottom:2px solid transparent;white-space:nowrap;transition:color .2s,border-color .2s;text-decoration:none;}
.nav-link:hover{color:var(--text);}
.nav-link.active{color:var(--accent);border-bottom-color:var(--accent);}

/* ── HERO ── */
.hero{padding:72px 48px 56px;border-bottom:1px solid var(--border);position:relative;overflow:hidden;}
.hero::before{content:'';position:absolute;top:-80px;right:-80px;width:480px;height:480px;background:radial-gradient(circle,rgba(200,240,96,.05) 0%,transparent 68%);pointer-events:none;}
.hero-eye{font-family:var(--font-m);font-size:11px;color:var(--accent);letter-spacing:.12em;text-transform:uppercase;margin-bottom:18px;}
.hero-title{font-family:var(--font-d);font-size:clamp(34px,5vw,56px);line-height:1.15;margin-bottom:14px;}
.hero-title em{font-style:italic;color:var(--accent);}
.hero-sub{font-size:14px;color:var(--text2);max-width:540px;line-height:1.85;margin-bottom:36px;}
.pills{display:flex;gap:10px;flex-wrap:wrap;}
.pill{display:flex;align-items:center;gap:7px;background:var(--surface);border:1px solid var(--border2);border-radius:20px;padding:5px 13px;font-size:12px;color:var(--text2);}
.pill .dot{width:6px;height:6px;border-radius:50%;}

/* ── MAIN ── */
.main{max-width:1080px;margin:0 auto;padding:0 28px 80px;}

/* ── SECTION ── */
.sec{padding:60px 0 44px;border-bottom:1px solid var(--border);}
.sec:last-child{border-bottom:none;}
.sec-hd{display:flex;align-items:flex-start;gap:18px;margin-bottom:36px;}
.sec-num{font-family:var(--font-m);font-size:11px;color:var(--text3);margin-top:5px;min-width:26px;}
.sec-title{font-size:21px;font-weight:700;line-height:1.3;}
.sec-desc{font-size:13px;color:var(--text2);margin-top:5px;line-height:1.7;}

/* 섹션 구분선 강조 — AX 인증 vs DX→AX 전환 */
.sec.ax-zone{border-left:3px solid var(--teal);padding-left:24px;}
.sec.dx-zone{border-left:3px solid var(--orange);padding-left:24px;}
.zone-badge{display:inline-flex;align-items:center;gap:6px;padding:4px 12px;border-radius:20px;font-size:11px;font-weight:700;font-family:var(--font-m);letter-spacing:.06em;margin-bottom:18px;}
.zone-badge.ax{background:var(--teal-dim);color:var(--teal);border:1px solid rgba(61,214,163,.25);}
.zone-badge.dx{background:var(--orange-dim);color:var(--orange);border:1px solid rgba(251,146,60,.25);}

/* ── GRID / CARD ── */
.g2{display:grid;grid-template-columns:repeat(2,1fr);gap:14px;}
.g3{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;}
.g4{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;}
.card{background:var(--surface);border:1px solid var(--border);border-radius:var(--rl);padding:22px;}
.card:hover{border-color:var(--border2);}
.cl{font-family:var(--font-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;margin-bottom:9px;}
.cl.teal{color:var(--teal);}
.cl.blue{color:var(--blue);}
.cl.purple{color:var(--purple);}
.cl.amber{color:var(--amber);}
.cl.orange{color:var(--orange);}
.cl.accent{color:var(--accent);}
.cl.gray{color:var(--text3);}
.ct{font-size:15px;font-weight:700;margin-bottom:8px;line-height:1.4;}
.cb{font-size:13px;color:var(--text2);line-height:1.75;}
.cb li{list-style:none;padding:3px 0 3px 14px;position:relative;}
.cb li::before{content:'·';position:absolute;left:0;color:var(--text3);}

/* ── 인사이트 박스 ── */
.insight{background:linear-gradient(135deg,rgba(200,240,96,.055),rgba(61,214,163,.045));border:1px solid rgba(200,240,96,.14);border-radius:var(--rl);padding:22px 26px;margin:20px 0;}
.insight .il{font-family:var(--font-m);font-size:10px;color:var(--accent);letter-spacing:.1em;text-transform:uppercase;margin-bottom:9px;}
.insight .it{font-size:13px;line-height:1.85;}

/* ── 경고 박스 ── */
.warn{background:var(--amber-dim);border:1px solid rgba(251,191,36,.22);border-radius:var(--r);padding:14px 18px;font-size:13px;color:var(--text2);margin-top:14px;}
.warn strong{color:var(--amber);}

/* ── PYRAMID ── */
.pyr{display:flex;flex-direction:column;gap:7px;align-items:center;margin:28px 0;}
.pyr-lv{border-radius:var(--r);padding:14px 22px;display:flex;align-items:center;justify-content:space-between;cursor:pointer;border:1px solid transparent;transition:transform .18s;}
.pyr-lv:hover{transform:translateX(4px);}
.lv-b{font-family:var(--font-m);font-size:10px;font-weight:500;padding:3px 8px;border-radius:4px;margin-right:12px;white-space:nowrap;}
.lv-t{font-size:15px;font-weight:700;flex:1;}
.lv-d{font-size:12px;color:var(--text2);text-align:right;max-width:240px;}
.lv4{background:var(--purple-dim);border-color:rgba(167,139,250,.22);width:54%;}
