.lv1 .lv-b{background:rgba(255,255,255,.08);color:var(--text2);}

/* ── 탭 ── */
.tab-bar{display:flex;gap:4px;background:var(--bg2);border:1px solid var(--border);border-radius:var(--r);padding:4px;margin-bottom:22px;flex-wrap:wrap;}
.tab-btn{padding:7px 16px;border-radius:7px;font-size:13px;font-family:var(--font-b);font-weight:500;color:var(--text2);background:transparent;border:none;cursor:pointer;transition:background .16s,color .16s;white-space:nowrap;}
.tab-btn.active{background:var(--surface2);color:var(--text);}
.tab-panel{display:none;}
.tab-panel.active{display:block;}

/* ── 테이블 ── */
.tbl{width:100%;border-collapse:collapse;font-size:13px;}
.tbl th{background:var(--surface);color:var(--text2);font-weight:500;font-size:11px;letter-spacing:.05em;padding:9px 14px;text-align:left;border-bottom:1px solid var(--border2);}
.tbl td{padding:11px 14px;border-bottom:1px solid var(--border);color:var(--text2);vertical-align:top;line-height:1.6;}
.tbl tr:last-child td{border-bottom:none;}
.tbl tr:hover td{background:rgba(255,255,255,.018);}
.tbl .tm{color:var(--text);font-weight:500;}
.badge{display:inline-block;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:500;}
.badge-teal{background:var(--teal-dim);color:var(--teal);}
.badge-blue{background:var(--blue-dim);color:var(--blue);}
.badge-purple{background:var(--purple-dim);color:var(--purple);}
.badge-amber{background:var(--amber-dim);color:var(--amber);}
.badge-orange{background:var(--orange-dim);color:var(--orange);}
.badge-gray{background:rgba(255,255,255,.07);color:var(--text2);}

/* ── 전환 플로우 테이블 ── */
.conv-wrap{background:var(--surface);border:1px solid var(--border);border-radius:var(--rl);overflow:hidden;}
.conv-hd{display:grid;grid-template-columns:1fr 40px 1fr;gap:12px;padding:12px 20px;background:var(--bg2);border-bottom:1px solid var(--border2);font-family:var(--font-m);font-size:10px;color:var(--text3);letter-spacing:.07em;align-items:center;text-align:center;}
.conv-row{display:grid;grid-template-columns:1fr 40px 1fr;gap:12px;padding:13px 20px;border-bottom:1px solid var(--border);align-items:center;font-size:13px;transition:background .15s;}
.conv-row:last-child{border-bottom:none;}
.conv-row:hover{background:rgba(255,255,255,.02);}
.conv-from{color:var(--text2);}
.conv-from strong{color:var(--text);}
.conv-arr{text-align:center;color:var(--orange);font-size:18px;}
.conv-to{color:var(--text);font-weight:500;}
.conv-note{font-size:11px;color:var(--text3);margin-top:3px;}

/* ── 타임라인 ── */
.tl{position:relative;padding-left:26px;}
.tl::before{content:'';position:absolute;left:6px;top:8px;bottom:8px;width:1px;background:linear-gradient(to bottom,var(--accent),var(--teal),var(--blue),var(--purple));opacity:.35;}
.tl-item{position:relative;margin-bottom:28px;}
.tl-dot{position:absolute;left:-22px;top:5px;width:13px;height:13px;border-radius:50%;border:2px solid;background:var(--bg);}
.tl-dot.accent{border-color:var(--accent);}
.tl-dot.teal{border-color:var(--teal);}
.tl-dot.blue{border-color:var(--blue);}
.tl-dot.purple{border-color:var(--purple);}
.tl-when{font-family:var(--font-m);font-size:11px;color:var(--text3);letter-spacing:.05em;margin-bottom:5px;}
.tl-h{font-size:15px;font-weight:700;margin-bottom:5px;}
.tl-b{font-size:13px;color:var(--text2);line-height:1.78;}

/* ── 메시지 박스 ── */
.msg-box{background:var(--bg2);border:1px solid var(--border2);border-radius:var(--rl);padding:24px 28px;font-size:13px;line-height:1.95;color:var(--text);white-space:pre-line;position:relative;}
.msg-label{font-family:var(--font-m);font-size:10px;color:var(--text3);letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px;}
.copy-btn{display:inline-flex;align-items:center;gap:5px;background:var(--surface2);border:1px solid var(--border2);border-radius:6px;padding:5px 12px;font-size:11px;font-family:var(--font-m);color:var(--text2);cursor:pointer;transition:background .14s,color .14s;float:right;margin-top:-4px;}
.copy-btn:hover{background:var(--accent);color:#000;border-color:var(--accent);}

/* ── 체크리스트 ── */
.chklist{list-style:none;}
.chklist li{display:flex;align-items:flex-start;gap:11px;padding:9px 0;border-bottom:1px solid var(--border);font-size:13px;color:var(--text2);}
.chklist li:last-child{border-bottom:none;}
.chk-box{width:17px;height:17px;border:1px solid var(--border2);border-radius:4px;flex-shrink:0;margin-top:2px;}
.chklist li strong{color:var(--text);}

/* ── FAQ ── */
.faq-item{border:1px solid var(--border);border-radius:var(--r);overflow:hidden;margin-bottom:7px;}
.faq-q{padding:15px 18px;font-size:14px;font-weight:500;cursor:pointer;display:flex;justify-content:space-between;align-items:center;background:var(--surface);user-select:none;}
.faq-q::after{content:'+';font-size:17px;color:var(--text3);transition:transform .2s;}
.faq-item.open .faq-q::after{transform:rotate(45deg);}
.faq-a{display:none;padding:15px 18px;font-size:13px;color:var(--text2);line-height:1.82;background:var(--bg2);border-top:1px solid var(--border);}
.faq-item.open .faq-a{display:block;}

/* ── 구분 헤더 (AX인증 vs DX→AX 대분류) ── */
.zone-header{display:flex;align-items:center;gap:14px;padding:18px 24px;border-radius:var(--rl);margin:32px 0 10px;border:1px solid;}
.zone-header.ax{background:linear-gradient(90deg,rgba(61,214,163,.08),transparent);border-color:rgba(61,214,163,.2);}
.zone-header.dx{background:linear-gradient(90deg,rgba(251,146,60,.08),transparent);border-color:rgba(251,146,60,.2);}
.zh-icon{font-size:22px;}
.zh-title{font-size:16px;font-weight:700;}
.zh-sub{font-size:12px;color:var(--text2);margin-top:2px;}

/* ── 비교 카드 강조 ── */
.compare-wrap{display:grid;grid-template-columns:1fr 1fr;gap:0;background:var(--surface);border:1px solid var(--border);border-radius:var(--rl);overflow:hidden;margin-bottom:24px;}
.cmp-col{padding:24px;}
.cmp-col:first-child{border-right:1px solid var(--border);}
.cmp-hd{font-size:13px;font-weight:700;padding:10px 24px;border-bottom:1px solid var(--border);}
.cmp-hd.ax-bg{background:rgba(61,214,163,.09);color:var(--teal);}
.cmp-hd.dx-bg{background:rgba(251,146,60,.09);color:var(--orange);}

/* ── 반응형 ── */
@media(max-width:680px){
  .g2,.g3,.g4{grid-template-columns:1fr;}
  .hero{padding:44px 20px 36px;}
  .main{padding:0 16px 60px;}
  .compare-wrap{grid-template-columns:1fr;}
  .cmp-col:first-child{border-right:none;border-bottom:1px solid var(--border);}
  .lv4{width:72%}.lv3{width:84%}.lv2{width:93%}
  .pyr-lv .lv-d{display:none;}
  .conv-hd,.conv-row{grid-template-columns:1fr 30px 1fr;}
}

/* ── 애니메이션 ── */
.fu{opacity:0;transform:translateY(18px);transition:opacity .48s ease,transform .48s ease;}
.fu.vis{opacity:1;transform:none;}
</style>
</head>
