<script>
// NAV 활성화
const secs = document.querySelectorAll('.sec');
const navLinks = document.querySelectorAll('.nav-link');
window.addEventListener('scroll', () => {
  let cur = '';
  secs.forEach(s => { if(window.scrollY >= s.offsetTop - 90) cur = s.id; });
  navLinks.forEach(l => l.classList.toggle('active', l.getAttribute('href') === '#'+cur));
});

// 일반 탭 전환
function switchTab(btn, panelId) {
  const bar = btn.closest('.tab-bar');
  const wrap = bar.parentElement;
  bar.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  wrap.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
  const t = wrap.querySelector('#'+panelId);
  if(t) t.classList.add('active');
}

// 인증 탭 + 피라미드 연동
function switchCert(btn, panelId) {
  const bar = btn.closest('.tab-bar');
  const wrap = bar.parentElement;
  bar.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  wrap.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
  const t = wrap.querySelector('#'+panelId);
  if(t) t.classList.add('active');
}
function showCertDetail(panelId) {
  const sec = document.getElementById('ax-cert');
  sec.querySelectorAll('.tab-panel').forEach(p => p.classList.remove('active'));
  const t = sec.querySelector('#'+panelId);
  if(t) t.classList.add('active');
  const num = panelId.replace('cert','');
  sec.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  const tb = sec.querySelector('#tab-cert'+num);
  if(tb) tb.classList.add('active');
}

// FAQ
function toggleFaq(el) { el.closest('.faq-item').classList.toggle('open'); }

// 복사
function copyMsg(id) {
  const el = document.getElementById(id);
  navigator.clipboard.writeText(el.innerText).then(() => {
    const btn = el.previousElementSibling;
    const orig = btn.innerText;
    btn.innerText = '복사됨 ✓';
    btn.style.background = 'var(--accent)';
    btn.style.color = '#000';
    setTimeout(() => { btn.innerText = orig; btn.style.background=''; btn.style.color=''; }, 2000);
  });
}

// 스크롤 애니메이션
const obs = new IntersectionObserver(es => es.forEach(e => { if(e.isIntersecting) e.target.classList.add('vis'); }), {threshold:.07});
document.querySelectorAll('.fu').forEach(el => obs.observe(el));
</script>
