  document.querySelectorAll('.result-card').forEach(c => c.classList.remove('show'));
  const el = document.getElementById(id);
  if (el) el.classList.add('show');
}

function updateProgress(cur, total) {
  const bar = document.getElementById('progressBar');
  bar.classList.add('show');
  document.getElementById('progressLabel').textContent = `질문 ${cur} / ${total}`;
  ['ps1','ps2'].forEach((id, i) => {
    const el = document.getElementById(id);
    el.classList.remove('done','active');
    if (i < cur - 1) el.classList.add('done');
    else if (i === cur - 1) el.classList.add('active');
  });
  const back = document.getElementById('backBtn');
  if (history.length > 0) back.classList.add('show');
  else back.classList.remove('show');
}

function answer(q, val) {
  history.push(q);
  state[q] = val;
  if (q === 'q1') {
    if (val === 'no') {
      showQ('q2a');
      updateProgress(2, 2);
    } else {
      showQ('q2b');
      updateProgress(2, 2);
    }
    document.getElementById('backBtn').classList.add('show');
  }
}

function showResult(id) {
  document.querySelectorAll('.q-card').forEach(c => c.classList.remove('show'));
  document.querySelectorAll('.result-card').forEach(c => c.classList.remove('show'));
  const el = document.getElementById('result-' + id);
  if (el) {
    el.classList.add('show');
    // 진행 바 완료 표시
    ['ps1','ps2'].forEach(id => {
      const p = document.getElementById(id);
      p.classList.remove('active');
      p.classList.add('done');
    });
    document.getElementById('progressLabel').textContent = '완료 ✓';
    document.getElementById('backBtn').classList.remove('show');
  }
}

function goBack() {
  if (history.length === 0) return;
  const prev = history.pop();
  document.querySelectorAll('.q-card, .result-card').forEach(c => c.classList.remove('show'));
  const el = document.getElementById(prev);
  if (el) el.classList.add('show');
  const cur = history.length + 1;
  updateProgress(cur, 2);
}

function restart() {
  state = { q1: null };
  history = [];
  document.querySelectorAll('.q-card, .result-card').forEach(c => c.classList.remove('show'));
  document.getElementById('progressBar').classList.remove('show');
  document.getElementById('backBtn').classList.remove('show');
  showQ('q1');
  updateProgress(1, 2);
  document.getElementById('finderSection').scrollIntoView({ behavior: 'smooth' });
}

// 아코디언
function toggleAcc(el) {
  el.closest('.acc-item').classList.toggle('open');
}
function toggleFaq(el) {
  el.closest('.faq-item').classList.toggle('open');
}

// 과정 탭
function switchCourse(btn, panelId) {
  document.querySelectorAll('.c-tab').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.course-panel').forEach(p => p.classList.remove('active'));
  document.getElementById(panelId).classList.add('active');
}

function showCourses() {
  document.getElementById('courseSection').scrollIntoView({ behavior: 'smooth' });
}
</script>
</body>
</html>
