<script>
/* 탭 */
function switchTab(btn, id) {
  document.querySelectorAll('.c-tab').forEach(b => b.classList.remove('on'));
  btn.classList.add('on');
  document.querySelectorAll('.c-panel').forEach(p => p.classList.remove('on'));
  document.getElementById(id).classList.add('on');
}

/* FAQ */
function toggleFq(btn) {
  btn.closest('.fq').classList.toggle('open');
}

/* NAV 스크롤 + 활성화 */
function scrollTo(id) {
  const el = document.getElementById(id);
  if (el) { el.scrollIntoView({ behavior: 'smooth', block: 'start' }); }
}
const navAs = document.querySelectorAll('.nav-a');
const sections = ['cover','principles','tracks','levels','conversion','timeline','courses','faq'];
window.addEventListener('scroll', () => {
  let cur = '';
  sections.forEach(id => {
    const el = document.getElementById(id);
    if (el && window.scrollY >= el.offsetTop - 80) cur = id;
  });
  const map = { cover:0, principles:1, tracks:2, levels:3, conversion:4, timeline:5, courses:6, faq:7 };
  navAs.forEach((a,i) => a.classList.toggle('on', i === map[cur]));
}, { passive: true });

/* 스크롤 reveal */
const obs = new IntersectionObserver(es => {
  es.forEach(e => { if (e.isIntersecting) e.target.classList.add('in'); });
}, { threshold: .07 });
document.querySelectorAll('.reveal').forEach(el => obs.observe(el));
</script>
